import React from 'react';

const Home = () => {
  // Service Card Component
  const ServiceCard = ({ title, desc, color }) => (
    <div style={{
      flex: '1', minWidth: '250px', margin: '10px', padding: '25px',
      backgroundColor: 'white', borderRadius: '15px', textAlign: 'center',
      boxShadow: '0 4px 6px rgba(0,0,0,0.1)', borderTop: `6px solid ${color}`
    }}>
      <h3 style={{ color: '#333', fontSize: '1.2rem' }}>{title}</h3>
      <p style={{ color: '#666', fontSize: '0.9rem' }}>{desc}</p>
      <button style={{
        backgroundColor: color, color: 'white', border: 'none',
        padding: '8px 20px', borderRadius: '20px', cursor: 'pointer'
      }}>Select</button>
    </div>
  );

  return (
    <div style={{ padding: '40px', fontFamily: 'Arial, sans-serif' }}>
      <div style={{ textAlign: 'center', marginBottom: '40px' }}>
        <h1 style={{ fontWeight: 'bold', color: '#222' }}>Logistics Aggregator Platform</h1>
        <p style={{ color: '#0056b3', fontWeight: 'bold' }}>One Solution for All Deliveries</p>
      </div>

      <div style={{ display: 'flex', flexWrap: 'wrap', justifyContent: 'center' }}>
        <ServiceCard title="Courier Services" desc="Domestic & Express Delivery" color="#2ecc71" />
        <ServiceCard title="Transport Services" desc="Roadways & Haulage Transport" color="#f1c40f" />
        <ServiceCard title="Packers & Movers" desc="Safe Home & Office Moving" color="#f39c12" />
        <ServiceCard title="Business MSME" desc="Bulk, 3PL & Supply Chain" color="#3498db" />
      </div>
    </div>
  );
};

export default Home;
